1021: 					if (this.isInternalMarkdownEmbed(node)) {
1022: 						candidates.push(node);
1023: 					}
1024: 					node.querySelectorAll<HTMLElement>(".internal-embed.markdown-embed").forEach((embed) => {
1025: 						candidates.push(embed);
1026: 					});
1027: 
1028: 					for (const embed of candidates) {
