1052: 	private isMarkdownViewShown(view: MarkdownView): boolean {
1053: 		const containerEl = view.containerEl as HTMLElement & { isShown?: () => boolean };
1054: 		if (typeof containerEl.isShown === "function") {
1055: 			try {
1056: 				return containerEl.isShown();
