1065: 	private queueExistingLivePreviewEmbeds(entry: LivePreviewObserverEntry): void {
1066: 		const before = entry.pendingEmbeds.size;
1067: 		entry.rootEl.querySelectorAll<HTMLElement>(".internal-embed.markdown-embed").forEach((embed) => {
1068: 			if (!embed.isConnected) return;
