1078: 	private async processObserverEntry(entry: LivePreviewObserverEntry): Promise<void> {
1079: 		if (!this.loaded) return;
1080: 		if (entry.processing) return;
1081: 		entry.processing = true;
1082: 
1083: 		try {
1084: 			if (!this.isInlineEditActive()) {
1085: 				entry.pendingEmbeds.clear();
1086: 				return;
1087: 			}
1088: 
1089: 			const livePreviewState = this.getLivePreviewState(entry);
1090: 			if (livePreviewState === "not-live") {
1091: 				entry.pendingEmbeds.clear();
1092: 				return;
1093: 			}
1094: 			if (livePreviewState === "unknown") {
1095: 				return;
1096: 			}
1097: 
1098: 			const view = entry.view;
1099: 			const ctx = {
1100: 				sourcePath: view.file!.path,
1101: 				addChild: () => {},
1102: 			} as unknown as MarkdownPostProcessorContext;
1103: 
1104: 			const embeds = Array.from(entry.pendingEmbeds).filter((el) => el.isConnected);
1105: 			entry.pendingEmbeds.clear();
1106: 
1107: 			for (const embedEl of embeds) {
